 1→import { NextResponse } from 'next/server';
 2→import { createClient } from '@/lib/supabase/server';
 3→
 4→export async function GET(request: Request) {
 5→  const { searchParams, origin } = new URL(request.url);
 6→  const code = searchParams.get('code');
 7→  const next = searchParams.get('next') ?? '/dashboard';
 8→
 9→  if (code) {
10→    const supabase = await createClient();
11→    const { error } = await supabase.auth.exchangeCodeForSession(code);
12→    if (!error) {
13→      const forwardedHost = request.headers.get('x-forwarded-host');
14→      const isLocalEnv = process.env.NODE_ENV === 'development';
15→      if (isLocalEnv) {
16→        return NextResponse.redirect(`${origin}${next}`);
17→      } else if (forwardedHost) {
18→        return NextResponse.redirect(`https://${forwardedHost}${next}`);
19→      } else {
20→        return NextResponse.redirect(`${origin}${next}`);
21→      }
22→    }
23→  }
24→
25→  return NextResponse.redirect(`${origin}/login?error=auth`);
26→}
