 13→interface UploadZoneProps {
 14→  organizationId: string;
 15→  onUploadComplete?: () => void;
 16→}
 17→
 18→interface UploadFile {
 19→  file: File;
 20→  progress: number;
 21→  status: 'pending' | 'uploading' | 'processing' | 'done' | 'error';
 22→  documentId?: string;
 23→  error?: string;
 24→}
 25→
 26→export function UploadZone({ organizationId, onUploadComplete }: UploadZoneProps) {
 27→  const [files, setFiles] = useState<UploadFile[]>([]);
 28→  const [isDragging, setIsDragging] = useState(false);
 29→  const [isUploading, setIsUploading] = useState(false);
 30→  const supabase = createClient();
 31→  const router = useRouter();
 32→
 33→  const handleDragOver = useCallback((e: React.DragEvent) => {
 34→    e.preventDefault();
 35→    setIsDragging(true);
 36→  }, []);
 37→
 38→  const handleDragLeave = useCallback(() => {
 39→    setIsDragging(false);
 40→  }, []);
 41→
 42→  const handleDrop = useCallback((e: React.DragEvent) => {
 43→    e.preventDefault();
 44→    setIsDragging(false);
 45→    const droppedFiles = Array.from(e.dataTransfer.files).filter(
 46→      (f) => f.type === 'application/pdf' || f.type.startsWith('image/')
 47→    );
 48→    addFiles(droppedFiles);
 49→  }, []);
 50→
 51→  const handleFileSelect = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
 52→    if (e.target.files) {
 53→      addFiles(Array.from(e.target.files));
 54→    }
 55→  }, []);
 56→
 57→  const addFiles = (newFiles: File[]) => {
 58→    const uploadFiles: UploadFile[] = newFiles.map((file) => ({
 59→      file,
 60→      progress: 0,
 61→      status: 'pending',
 62→    }));
 63→    setFiles((prev) => [...prev, ...uploadFiles]);
 64→  };
 65→
 66→  const removeFile = (index: number) => {
 67→    setFiles((prev) => prev.filter((_, i) => i !== index));
 68→  };
 69→
 70→  const uploadAll = async () => {
 71→    setIsUploading(true);
 72→
 73→    for (let i = 0; i < files.length; i++) {
 74→      if (files[i].status !== 'pending') continue;
 75→
 76→      // Update status to uploading
 77→      setFiles((prev) =>
 78→        prev.map((f, idx) => (idx === i ? { ...f, status: 'uploading' as const, progress: 10 } : f))
 79→      );
 80→
 81→      try {
 82→        const file = files[i].file;
 83→        const fileExt = file.name.split('.').pop();
 84→        const filePath = `${organizationId}/${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
 85→
 86→        // Upload to Supabase Storage
 87→        setFiles((prev) =>
 88→          prev.map((f, idx) => (idx === i ? { ...f, progress: 30 } : f))
 89→        );
 90→
 91→        const { error: uploadError } = await supabase.storage
 92→          .from('documents')
 93→          .upload(filePath, file);
 94→
 95→        if (uploadError) throw uploadError;
 96→
 97→        setFiles((prev) =>
 98→          prev.map((f, idx) => (idx === i ? { ...f, progress: 60 } : f))
 99→        );
100→
101→        // Create document record
102→        const { data: doc, error: dbError } = await supabase
103→          .from('documents')
104→          .insert({
105→            organization_id: organizationId,
106→            uploaded_by: (await supabase.auth.getUser()).data.user?.id,
107→            file_name: file.name,
108→            file_url: filePath,
109→            file_size: file.size,
110→            file_type: file.type,
111→            status: 'pending',
112→          })
113→          .select()
114→          .single();
115→
116→        if (dbError) throw dbError;
117→
118→        setFiles((prev) =>
119→          prev.map((f, idx) =>
120→            idx === i ? { ...f, progress: 80, status: 'processing' as const, documentId: doc.id } : f
121→          )
122→        );
123→
124→        // Trigger AI processing
125→        const processResponse = await fetch('/api/documents/process', {
126→          method: 'POST',
127→          headers: { 'Content-Type': 'application/json' },
128→          body: JSON.stringify({ documentId: doc.id }),
129→        });
130→
131→        if (!processResponse.ok) {
132→          const err = await processResponse.json();
133→          throw new Error(err.error || 'Processing failed');
134→        }
135→
136→        setFiles((prev) =>
137→          prev.map((f, idx) =>
138→            idx === i ? { ...f, progress: 100, status: 'done' as const } : f
139→          )
140→        );
141→      } catch (error) {
142→        const message = error instanceof Error ? error.message : 'Upload failed';
143→        setFiles((prev) =>
144→          prev.map((f, idx) =>
145→            idx === i ? { ...f, status: 'error' as const, error: message } : f
146→          )
147→        );
148→        toast.error(`Failed to upload ${files[i].file.name}: ${message}`);
149→      }
150→    }
151→
152→    setIsUploading(false);
153→    toast.success('Upload complete');
154→    onUploadComplete?.();
155→    router.refresh();
156→  };
157→
158→  const formatSize = (bytes: number) => {
159→    if (bytes < 1024) return bytes + ' B';
160→    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
161→    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
162→  };
163→
164→  return (
165→    <div className="space-y-4">
166→      <div
167→        onDragOver={handleDragOver}
168→        onDragLeave={handleDragLeave}
169→        onDrop={handleDrop}
170→        className={cn(
171→          'relative rounded-lg border-2 border-dashed p-12 text-center transition-colors cursor-pointer',
172→          isDragging
173→            ? 'border-primary bg-primary/5'
174→            : 'border-muted-foreground/25 hover:border-primary/50'
175→        )}
176→        onClick={() => document.getElementById('file-input')?.click()}
177→      >
178→        <input
179→          id="file-input"
180→          type="file"
181→          multiple
182→          accept=".pdf,.png,.jpg,.jpeg,.tiff,.webp"
183→          className="hidden"
184→          onChange={handleFileSelect}
185→        />
186→        <Upload className="mx-auto h-10 w-10 text-muted-foreground mb-4" />
187→        <p className="text-lg font-medium">Drag files here or click to browse</p>
188→        <p className="text-sm text-muted-foreground mt-1">
189→          Supports PDF, PNG, JPG, TIFF, WebP
190→        </p>
191→      </div>
192→
193→      {files.length > 0 && (
194→        <div className="space-y-3">
195→          {files.map((uploadFile, index) => (
196→            <Card key={index} className="p-4">
197→              <div className="flex items-center gap-3">
198→                <FileText className="h-8 w-8 text-muted-foreground shrink-0" />
199→                <div className="flex-1 min-w-0">
200→                  <p className="text-sm font-medium truncate">{uploadFile.file.name}</p>
201→                  <p className="text-xs text-muted-foreground">
202→                    {formatSize(uploadFile.file.size)}
203→                    {uploadFile.status === 'error' && (
204→                      <span className="text-destructive ml-2">{uploadFile.error}</span>
205→                    )}
206→                    {uploadFile.status === 'done' && (
207→                      <span className="text-green-600 ml-2">Complete</span>
208→                    )}
209→                    {uploadFile.status === 'processing' && (
210→                      <span className="text-blue-600 ml-2">Processing with AI...</span>
211→                    )}
212→                  </p>
213→                  {(uploadFile.status === 'uploading' || uploadFile.status === 'processing') && (
214→                    <Progress value={uploadFile.progress} className="h-1.5 mt-2" />
215→                  )}
216→                </div>
217→                {uploadFile.status === 'pending' && (
218→                  <Button
219→                    variant="ghost"
220→                    size="icon"
221→                    className="shrink-0"
222→                    onClick={(e) => {
223→                      e.stopPropagation();
224→                      removeFile(index);
225→                    }}
226→                  >
227→                    <X className="h-4 w-4" />
228→                  </Button>
229→                )}
230→                {uploadFile.status === 'done' && (
231→                  <span className="text-green-600 text-sm font-medium">Done</span>
232→                )}
233→              </div>
234→            </Card>
235→          ))}
236→
237→          <Button
238→            onClick={uploadAll}
239→            disabled={isUploading || files.every((f) => f.status !== 'pending')}
240→            className="w-full"
241→          >
242→            {isUploading ? (
243→              <>
244→                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
245→                Processing...
246→              </>
247→            ) : (
248→              <>
249→                <Upload className="mr-2 h-4 w-4" />
250→                Upload & Process All
251→              </>
252→            )}
253→          </Button>
254→        </div>
255→      )}
256→    </div>
257→  );
258→}
