 4→const PUBLIC_ROUTES = ['/', '/pricing', '/login', '/signup', '/forgot-password', '/callback', '/api/health'];
 5→
 6→export async function updateSession(request: NextRequest) {
 7→  const { pathname } = request.nextUrl;
 8→
 9→  // Skip auth check for public routes and public survey pages
10→  const isPublic = PUBLIC_ROUTES.includes(pathname) || pathname.startsWith('/s/');
11→  if (isPublic) {
12→    return NextResponse.next({ request });
13→  }
14→
15→  let supabaseResponse = NextResponse.next({
16→    request,
17→  });
18→
19→  const supabase = createServerClient(
20→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
21→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
22→    {
23→      cookies: {
24→        getAll() {
25→          return request.cookies.getAll();
26→        },
27→        setAll(cookiesToSet) {
28→          cookiesToSet.forEach(({ name, value }) =>
29→            request.cookies.set(name, value)
30→          );
31→          supabaseResponse = NextResponse.next({
32→            request,
33→          });
34→          cookiesToSet.forEach(({ name, value, options }) =>
35→            supabaseResponse.cookies.set(name, value, options)
36→          );
37→        },
38→      },
39→    }
40→  );
41→
42→  const {
43→    data: { user },
44→  } = await supabase.auth.getUser();
45→
46→  // Protect dashboard routes
47→  if (
48→    !user &&
49→    request.nextUrl.pathname.startsWith('/dashboard')
50→  ) {
51→    const url = request.nextUrl.clone();
52→    url.pathname = '/login';
53→    return NextResponse.redirect(url);
54→  }
55→
56→  // Redirect logged-in users away from auth pages
57→  if (
58→    user &&
59→    (request.nextUrl.pathname === '/login' || request.nextUrl.pathname === '/signup')
60→  ) {
61→    const url = request.nextUrl.clone();
62→    url.pathname = '/dashboard';
63→    return NextResponse.redirect(url);
64→  }
65→
66→  return supabaseResponse;
67→}
